// src/App.js
import { useEffect, useState } from 'react';
import { Routes, Route } from 'react-router-dom';
import Nav from './components/Nav';
// eslint-disable-next-line no-unused-vars
import ProtectedRoute from './components/ProtectedRoute';
import SplashPage from './pages/SplashPage';
import HomePage from './pages/HomePage';
import AboutPage from './pages/AboutPage';
import ContactPage from './pages/ContactPage';
import RegisterPage from './pages/RegisterPage';
import LoginPage from './pages/LoginPage';
import ProfilePage from './pages/ProfilePage';
import AdminPage from './pages/AdminPage';
import PostPage from './pages/PostPage';
import WritePostPage from './pages/WritePostPage';
import EditPostPage from './pages/EditPostPage';

function App() {
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const timer = window.setTimeout(() => {
      setIsLoading(false);
    }, 900);

    return () => window.clearTimeout(timer);
  }, []);

  if (isLoading) {
    return (
      <div style={{
        minHeight: '100vh',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        flexDirection: 'column',
        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
        color: '#ffffff',
        textAlign: 'center',
        padding: '2rem',
      }}>
        <div style={{ fontSize: '4rem', marginBottom: '1rem' }}>💜</div>
        <div style={{
          width: 72,
          height: 72,
          borderRadius: '50%',
          border: '8px solid rgba(255,255,255,0.3)',
          borderTop: '8px solid #ffffff',
          animation: 'spin 1s linear infinite',
        }} />
        <p style={{ marginTop: '1rem', fontSize: '1.1rem' }}>Loading website...</p>
        <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
      </div>
    );
  }

  return (
    <>
      <Nav />
      <Routes>
        {/* Public routes — anyone can visit */}
        <Route path='/' element={<SplashPage />} />
        <Route path='/home' element={<HomePage />} />
        <Route path='/about' element={<AboutPage />} />
        <Route path='/contact' element={<ContactPage />} />
        <Route path='/login' element={<LoginPage />} />
        <Route path='/register' element={<RegisterPage />} />
        <Route path='/profile' element={<ProtectedRoute><ProfilePage /></ProtectedRoute>} />
        <Route path='/admin' element={<ProtectedRoute role='admin'><AdminPage /></ProtectedRoute>} />
        <Route path='/post/:id' element={<PostPage />} />
        <Route path='/post/:id/edit' element={<ProtectedRoute><EditPostPage /></ProtectedRoute>} />
        <Route path='/write-post' element={<ProtectedRoute><WritePostPage /></ProtectedRoute>} />
        {/* Add more routes here as you create the pages */}
      </Routes>
    </>
  );
}

export default App;
